F=(-1,-3.82);
I=(1,-3.82);
draw(A--B--C--D--I--F--G--H--cycle,linewidth(0.7));
label("$A$",A,N);
label("$B$",B,N);
label("$C$",C,E);
label("$D$",D,E);
label("$E$",I,S);
label("$F$",F,S);
label("$G$",G,W);
label("$H$",H,W);
draw(A--F);
draw(B--I);
draw(A--I,dashed);
draw(B--F,dashed);
label("$o$",(0,-1.42),E);
[/asy]

